    void base(String title){root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(cream);TextView bar=text(title,21,Color.WHITE);bar.setTypeface(null,Typeface.BOLD);bar.setGravity(Gravity.CENTER_VERTICAL);bar.setBackgroundColor(tealDark);bar.setPadding(dp(22),dp(15),dp(22),dp(12));root.addView(bar,new LinearLayout.LayoutParams(-1,dp(64)));progressHeader=new LinearLayout(this);progressHeader.setOrientation(LinearLayout.VERTICAL);progressHeader.setPadding(dp(20),dp(5),dp(20),dp(5));progressHeader.setBackgroundColor(Color.rgb(236,242,239));topProgressText=text("",12,muted);topProgressText.setPadding(0,0,0,dp(2));progressHeader.addView(topProgressText);topProgress=progress(1,0,teal);progressHeader.addView(topProgress,new LinearLayout.LayoutParams(-1,dp(4)));progressHeader.setVisibility(View.GONE);root.addView(progressHeader,new LinearLayout.LayoutParams(-1,dp(32)));ScrollView sc=new ScrollView(this);sc.setFillViewport(true);content=new LinearLayout(this);content.setOrientation(LinearLayout.VERTICAL);content.setGravity(Gravity.CENTER_HORIZONTAL);content.setPadding(dp(20),dp(20),dp(20),dp(24));sc.addView(content,new ScrollView.LayoutParams(-1,-1));root.addView(sc,new LinearLayout.LayoutParams(-1,0,1));actions=new LinearLayout(this);actions.setOrientation(LinearLayout.VERTICAL);actions.setPadding(dp(12),dp(8),dp(12),dp(12));actions.setBackgroundColor(Color.rgb(236,242,239));actions.setVisibility(View.GONE);root.addView(actions,new LinearLayout.LayoutParams(-1,-2));setContentView(root);}
    void gap(int h){Space s=new Space(this);content.addView(s,new LinearLayout.LayoutParams(1,dp(h)));}
