    ProgressBar progress(int max,int value,int color){ProgressBar p=new ProgressBar(this,null,android.R.attr.progressBarStyleHorizontal);p.setMax(Math.max(1,max));p.setProgress(Math.min(value,Math.max(1,max)));if(Build.VERSION.SDK_INT>=21)p.setProgressTintList(android.content.res.ColorStateList.valueOf(color));return p;}
    void progressBlock(LinearLayout box,String title,int value,int max,int color){TextView t=text(title,16,ink);t.setTypeface(null,Typeface.BOLD);box.addView(t);box.addView(progress(max,value,color),new LinearLayout.LayoutParams(-1,dp(10)));box.addView(text(value+" / "+max+(max>0?String.format(Locale.getDefault(),"  ·  %.1f%%",value*100.0/max):""),14,muted));}

