        LinearLayout row=new LinearLayout(this);Button books=button("词库管理");color(books,Color.rgb(62,92,132));books.setOnClickListener(v->showBookManager());Button check=button(db.checkedToday()?"✓ 今日已打卡":"今日打卡");color(check,db.checkedToday()?tealDark:amber);check.setOnClickListener(v->showCheckIn());row.addView(books,new LinearLayout.LayoutParams(0,dp(58),1));LinearLayout.LayoutParams cp=new LinearLayout.LayoutParams(0,dp(58),1);cp.setMargins(dp(8),0,0,0);row.addView(check,cp);addCard(row);
